import React from 'react';
import { Card, Stack, Box, Divider, Text, Heading, Icon, MotionKeyframes } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function pickConditionIcon(condition: string): string {
  const key = (condition ?? '').toLowerCase();
  if (key.includes('thunder') || key.includes('storm')) return '⛈️';
  if (key.includes('snow') || key.includes('sleet') || key.includes('hail')) return '❄️';
  if (key.includes('rain') || key.includes('drizzle')) return '🌧️';
  if (key.includes('fog') || key.includes('mist') || key.includes('haze')) return '🌫️';
  if (key.includes('cloud') || key.includes('overcast')) return '☁️';
  if (key.includes('wind') || key.includes('breezy')) return '💨';
  if (key.includes('partly') || key.includes('mostly')) return '⛅';
  if (key.includes('clear') || key.includes('sun') || key.includes('hot')) return '☀️';
  return '🌤️';
}

function getConditionTone(condition: string): string {
  const key = (condition ?? '').toLowerCase();
  if (key.includes('rain') || key.includes('storm') || key.includes('thunder')) return 'var(--ggui-color-info-500, #0284c7)';
  if (key.includes('snow') || key.includes('fog') || key.includes('mist') || key.includes('haze')) return 'var(--ggui-color-onSurfaceVariant, #52525b)';
  if (key.includes('cloud')) return 'var(--ggui-color-primary-700, #0369a1)';
  return 'var(--ggui-color-warning-500, #d97706)';
}

export default function GeneratedComponent(props: Props) {
  const city = props.city ?? '—';
  const temperature = Math.round(props.temperature ?? 0);
  const condition = props.condition ?? 'Unknown';
  const humidity = Math.round(props.humidity ?? 0);
  const windSpeed = Math.round(props.windSpeed ?? 0);
  const unit = props.unit ?? 'C';
  const forecast = props.forecast ?? [];

  const currentIcon = pickConditionIcon(condition);
  const accent = getConditionTone(condition);

  return (
    <>
      <MotionKeyframes />
      <Card shadow="md" radius="lg" border={true} padding={0} aria-label={`Weather in ${city}`}>
        <Box
          padding={16}
          style={{
            background: 'linear-gradient(180deg, var(--ggui-color-primary-50, #f0f9ff) 0%, var(--ggui-color-surface, #fafafa) 100%)',
          }}
        >
          <Stack gap={16}>
            <Stack direction="horizontal" justify="between" align="start" gap={16}>
              <Stack gap={4}>
                <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">
                  {city}
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {condition}
                </Text>
              </Stack>
              <Box
                padding={12}
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
                style={{
                  backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  color: accent,
                  boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px 0 rgba(0,0,0,0.05))',
                }}
              >
                <Icon name={currentIcon} size={40} color={accent} />
              </Box>
            </Stack>

            <Stack gap={4} align="start">
              <Stack direction="horizontal" align="end" gap={4}>
                <Heading
                  level={1}
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {temperature}
                </Heading>
                <Text
                  is="span"
                  variant="body"
                  weight="semibold"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  style={{ paddingBottom: 'var(--ggui-spacing-1, 4px)' }}
                >
                  °{unit}
                </Text>
              </Stack>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Feels calm and current weather details are shown below.
              </Text>
            </Stack>

            <Stack direction="horizontal" gap={12} wrap={true}>
              <Box
                padding={12}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                style={{
                  flex: '1 1 160px',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                }}
              >
                <Stack direction="horizontal" align="center" gap={8}>
                  <Icon name="droplets" size={20} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Stack gap={2}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Humidity
                    </Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {humidity}%
                    </Text>
                  </Stack>
                </Stack>
              </Box>

              <Box
                padding={12}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                style={{
                  flex: '1 1 160px',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                }}
              >
                <Stack direction="horizontal" align="center" gap={8}>
                  <Icon name="wind" size={20} color="var(--ggui-color-primary-600, #0284c7)" />
                  <Stack gap={2}>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      Wind Speed
                    </Text>
                    <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                      {windSpeed} km/h
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={0} />

        <Box padding={16}>
          <Stack gap={12}>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              5-Day Forecast
            </Text>

            <Box role="list">
              <Stack direction="horizontal" gap={8} wrap={true}>
                {forecast.map((item, index) => {
                  const day = item.day ?? '—';
                  const icon = item.icon ?? '🌤️';
                  const high = item.high ?? 0;
                  const low = item.low ?? 0;

                  return (
                    <Box
                      key={`${day}-${index}`}
                      role="listitem"
                      padding={12}
                      borderRadius="var(--ggui-shape-radius-md, 8px)"
                      background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                      style={{
                        flex: '1 1 92px',
                        minWidth: '92px',
                        border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                        transition: 'background-color 200ms ease, transform 200ms ease, border-color 200ms ease',
                      }}
                    >
                      <Stack gap={8} align="center">
                        <Text variant="label" align="center" color="var(--ggui-color-onSurface, #18181b)">
                          {day}
                        </Text>
                        <Text is="span" variant="bodyLarge" align="center" style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)', lineHeight: 1 }}>
                          {icon}
                        </Text>
                        <Stack gap={2} align="center">
                          <Text variant="caption" align="center" color="var(--ggui-color-onSurface, #18181b)">
                            H: {Math.round(high)}°
                          </Text>
                          <Text variant="caption" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                            L: {Math.round(low)}°
                          </Text>
                        </Stack>
                      </Stack>
                    </Box>
                  );
                })}
              </Stack>
            </Box>
          </Stack>
        </Box>
      </Card>
    </>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Badge,
  Box,
  Button,
  Card,
  Checkbox,
  Container,
  Heading,
  Input,
  MotionKeyframes,
  Progress,
  RadioGroup,
  Stack,
  Text,
  TextArea,
  Toast,
} from '@ggui-ai/design/primitives';

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: SubmissionPayload) => void;
}

type SubmissionPayload = {
  name: string;
  email: string;
  satisfaction: number;
  features: string[];
  comments: string;
};

function isValidEmail(email: string): boolean {
  const value = email.trim();
  if (!value) return false;
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

function getSatisfactionFallback(labels: string[]): number {
  return labels.length >= 5 ? 3 : Math.max(1, Math.ceil(labels.length / 2));
}

export default function GeneratedComponent(props: Props) {
  const featureOptions = props.featureOptions ?? [];
  const satisfactionLabels = props.satisfactionLabels ?? [];

  const [step, setStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [emailTouched, setEmailTouched] = useState<boolean>(false);
  const [satisfaction, setSatisfaction] = useState<string>(String(getSatisfactionFallback(satisfactionLabels)));
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [isSubmitting, setIsSubmitting] = useState<boolean>(false);
  const [submitState, setSubmitState] = useState<'idle' | 'success' | 'error'>('idle');
  const [submitMessage, setSubmitMessage] = useState<string>('');
  const [stepError, setStepError] = useState<string>('');

  useEffect(() => {
    const data = (globalThis as unknown as { __gguiAgentData?: Partial<SubmissionPayload> }).__gguiAgentData;
    if (!data) return;
    if (typeof data.name === 'string') setName(data.name);
    if (typeof data.email === 'string') setEmail(data.email);
    if (typeof data.satisfaction === 'number') setSatisfaction(String(data.satisfaction));
    if (Array.isArray(data.features)) setFeatures(data.features.filter((item): item is string => typeof item === 'string'));
    if (typeof data.comments === 'string') setComments(data.comments);
  }, []);

  const nameError = useMemo(() => {
    if (!name.trim()) return 'Name is required.';
    return '';
  }, [name]);

  const emailError = useMemo(() => {
    if (!email.trim()) return emailTouched ? 'Email is required.' : '';
    if (!isValidEmail(email)) return 'Please enter a valid email address.';
    return '';
  }, [email, emailTouched]);

  const satisfactionOptions = useMemo(() => {
    const source = satisfactionLabels.length >= 5 ? satisfactionLabels.slice(0, 5) : satisfactionLabels;
    return source.map((label, index) => ({
      value: String(index + 1),
      label,
      description: `${index + 1} of ${Math.max(5, satisfactionLabels.length)}`,
    }));
  }, [satisfactionLabels]);

  const commentsMax = 500;

  const canContinueFromStep1 = !nameError && !emailError && !!name.trim() && !!email.trim();
  const canContinueFromStep2 = satisfactionOptions.length > 0 && !!satisfaction;
  const canSubmit = canContinueFromStep1 && canContinueFromStep2 && !isSubmitting;

  const payload: SubmissionPayload = {
    name: name.trim(),
    email: email.trim(),
    satisfaction: Number.parseInt(satisfaction, 10) || getSatisfactionFallback(satisfactionLabels),
    features,
    comments: comments.trim(),
  };

  const goNext = () => {
    setStepError('');
    if (step === 1) {
      setEmailTouched(true);
      if (!canContinueFromStep1) {
        setStepError('Please complete Step 1 before continuing.');
        return;
      }
    }
    if (step === 2 && !canContinueFromStep2) {
      setStepError('Please choose a satisfaction rating.');
      return;
    }
    if (step < 5) setStep(step + 1);
  };

  const goBack = () => {
    setStepError('');
    if (step > 1) setStep(step - 1);
  };

  const toggleFeature = (feature: string) => {
    setFeatures((current) =>
      current.includes(feature) ? current.filter((item) => item !== feature) : [...current, feature]
    );
  };

  const handleSubmit = async () => {
    setStepError('');
    setEmailTouched(true);

    if (!canSubmit) {
      setStepError('Please resolve the validation issues before submitting.');
      return;
    }

    try {
      setIsSubmitting(true);
      setSubmitState('idle');
      setSubmitMessage('');
      await Promise.resolve();
      setSubmitState('success');
      setSubmitMessage('Survey submitted successfully.');
      props.onSubmit?.(payload);
      setStep(5);
    } catch {
      setSubmitState('error');
      setSubmitMessage('We could not submit your survey. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const stepLabel = step === 5 ? 'Review & Submit' : `Step ${step} of 4`;
  const progressValue = Math.min(step, 4);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-4, 16px)">
        <Card shadow="md" padding="var(--ggui-spacing-6, 24px)" radius="lg">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Stack direction="horizontal" align="center" justify="between" gap="var(--ggui-spacing-2, 8px)">
                <Heading level={2}>Multi-step Survey</Heading>
                <Badge variant="primary" size="md">
                  {stepLabel}
                </Badge>
              </Stack>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Share your feedback in four quick steps. Review everything before submitting.
              </Text>
            </Stack>

            <Progress value={progressValue} max={4} size="md" showLabel />

            {stepError ? (
              <Alert variant="warning" title="Action required">
                {stepError}
              </Alert>
            ) : null}

            {submitState !== 'idle' ? (
              <Toast
                visible
                variant={submitState === 'success' ? 'success' : 'error'}
                title={submitState === 'success' ? 'Success' : 'Submission failed'}
                message={submitMessage}
              />
            ) : null}

            {step === 1 ? (
              <Card shadow="none" border padding={0} radius="lg">
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Heading level={3}>About you</Heading>
                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    required
                    placeholder="John Doe"
                    error={name.trim() ? '' : 'Name is required.'}
                    aria-label="Name"
                  />
                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={(value) => {
                      setEmail(value);
                      setEmailTouched(true);
                    }}
                    required
                    placeholder="john@example.com"
                    error={emailError}
                    aria-label="Email"
                  />
                </Stack>
              </Card>
            ) : null}

            {step === 2 ? (
              <Card shadow="none" border padding={0} radius="lg">
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Heading level={3}>Satisfaction</Heading>
                  <RadioGroup
                    label="How satisfied are you?"
                    value={satisfaction}
                    onChange={setSatisfaction}
                    options={satisfactionOptions}
                    direction="vertical"
                    error={satisfactionOptions.length ? '' : 'No satisfaction labels were provided.'}
                  />
                </Stack>
              </Card>
            ) : null}

            {step === 3 ? (
              <Card shadow="none" border padding={0} radius="lg">
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Heading level={3}>Feature interests</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Select any features you are interested in.
                  </Text>
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    {featureOptions.length > 0 ? (
                      featureOptions.map((option) => (
                        <Checkbox
                          key={option}
                          label={option}
                          checked={features.includes(option)}
                          onChange={() => toggleFeature(option)}
                        />
                      ))
                    ) : (
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        No feature options were provided.
                      </Text>
                    )}
                  </Stack>
                </Stack>
              </Card>
            ) : null}

            {step === 4 ? (
              <Card shadow="none" border padding={0} radius="lg">
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Heading level={3}>Comments</Heading>
                  <TextArea
                    label="Open-ended comments"
                    value={comments}
                    onChange={setComments}
                    rows={6}
                    placeholder="Tell us anything else you'd like us to know..."
                    maxLength={commentsMax}
                    showCount
                    helperText="Optional"
                    aria-label="Open-ended comments"
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    You can include suggestions, concerns, or anything that would help us improve.
                  </Text>
                </Stack>
              </Card>
            ) : null}

            {step === 5 ? (
              <Card shadow="none" border padding={0} radius="lg">
                <Stack gap="var(--ggui-spacing-4, 16px)">
                  <Heading level={3}>Final review</Heading>
                  <Box
                    padding="var(--ggui-spacing-4, 16px)"
                    background="var(--ggui-color-primary-50, #f0f9ff)"
                    borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  >
                    <Stack gap="var(--ggui-spacing-3, 12px)">
                      <ReviewRow label="Name" value={payload.name} />
                      <ReviewRow label="Email" value={payload.email} />
                      <ReviewRow
                        label="Satisfaction"
                        value={
                          satisfactionOptions[Number.parseInt(satisfaction, 10) - 1]?.label ??
                          satisfactionLabels[Number.parseInt(satisfaction, 10) - 1] ??
                          satisfaction
                        }
                      />
                      <ReviewRow
                        label="Features"
                        value={features.length > 0 ? features.join(', ') : 'None selected'}
                      />
                      <ReviewRow label="Comments" value={comments.trim() || 'No comments'} />
                    </Stack>
                  </Box>
                </Stack>
              </Card>
            ) : null}

            <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-3, 12px)">
              <Button
                variant="outline"
                onClick={goBack}
                disabled={step === 1 || isSubmitting}
                aria-label="Back"
              >
                Back
              </Button>

              <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                {step < 5 ? (
                  <Button
                    variant="primary"
                    onClick={goNext}
                    disabled={
                      isSubmitting ||
                      (step === 1 && !canContinueFromStep1) ||
                      (step === 2 && !canContinueFromStep2)
                    }
                    aria-label="Next"
                  >
                    Next
                  </Button>
                ) : (
                  <Button
                    variant="primary"
                    onClick={handleSubmit}
                    loading={isSubmitting}
                    disabled={!canSubmit}
                    aria-label="Submit Survey"
                  >
                    Submit Survey
                  </Button>
                )}
              </Stack>
            </Stack>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

function ReviewRow({ label, value }: { label: string; value: string }) {
  return (
    <Stack direction="horizontal" justify="between" align="start" gap="var(--ggui-spacing-3, 12px)">
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
        {label}
      </Text>
      <Text variant="bodySmall" align="right">
        {value}
      </Text>
    </Stack>
  );
}

import React, { useEffect, useMemo, useState } from 'react';
import { Badge, Box, Card, Container, Divider, Heading, Input, MotionKeyframes, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  /** Full periodic table element data */
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>;
}

type ElementRecord = Props['elements'][number];

const categoryStyles: Record<string, { background: string; color: string; border: string }> = {
  'alkali-metal': {
    background: 'var(--ggui-color-primary-100, #e0f2fe)',
    color: 'var(--ggui-color-primary-800, #075985)',
    border: 'var(--ggui-color-primary-200, #bae6fd)',
  },
  'alkaline-earth-metal': {
    background: 'var(--ggui-color-warning-100, #fef3c7)',
    color: 'var(--ggui-color-warning-800, #92400e)',
    border: 'var(--ggui-color-warning-200, #fde68a)',
  },
  'transition-metal': {
    background: 'var(--ggui-color-info-100, #cffafe)',
    color: 'var(--ggui-color-info-800, #155e75)',
    border: 'var(--ggui-color-info-200, #a5f3fc)',
  },
  'post-transition-metal': {
    background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    color: 'var(--ggui-color-onSurface, #18181b)',
    border: 'var(--ggui-color-outlineVariant, #e4e4e7)',
  },
  metalloid: {
    background: 'var(--ggui-color-success-100, #dcfce7)',
    color: 'var(--ggui-color-success-800, #166534)',
    border: 'var(--ggui-color-success-200, #bbf7d0)',
  },
  nonmetal: {
    background: 'var(--ggui-color-primary-50, #f0f9ff)',
    color: 'var(--ggui-color-primary-700, #0369a1)',
    border: 'var(--ggui-color-primary-200, #bae6fd)',
  },
  halogen: {
    background: 'var(--ggui-color-warning-100, #fef3c7)',
    color: 'var(--ggui-color-warning-700, #b45309)',
    border: 'var(--ggui-color-warning-200, #fde68a)',
  },
  'noble-gas': {
    background: 'var(--ggui-color-info-100, #cffafe)',
    color: 'var(--ggui-color-info-700, #0e7490)',
    border: 'var(--ggui-color-info-200, #a5f3fc)',
  },
  lanthanide: {
    background: 'var(--ggui-color-primary-50, #f0f9ff)',
    color: 'var(--ggui-color-primary-700, #0369a1)',
    border: 'var(--ggui-color-primary-200, #bae6fd)',
  },
  actinide: {
    background: 'var(--ggui-color-error-100, #fee2e2)',
    color: 'var(--ggui-color-error-700, #b91c1c)',
    border: 'var(--ggui-color-error-200, #fecaca)',
  },
  unknown: {
    background: 'var(--ggui-color-outlineVariant, #e4e4e7)',
    color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
    border: 'var(--ggui-color-outline, #d4d4d8)',
  },
};

function normalizeCategory(category?: string): string {
  return (category ?? 'unknown').trim().toLowerCase() || 'unknown';
}

function formatAtomicWeight(value?: number): string {
  return value ?? value === 0 ? String(value) : '—';
}

function formatDetailValue(value: string | number | undefined): string {
  if (value === undefined || value === null) return '—';
  return String(value);
}

function formatCategoryLabel(category?: string): string {
  return category ?? 'unknown';
}

export default function GeneratedComponent(props: Props) {
  const elements = props.elements ?? [];
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const filteredElements = useMemo(() => {
    const q = query.trim().toLowerCase();
    const base = elements
      .slice()
      .sort((a, b) => (a.row ?? 0) - (b.row ?? 0) || (a.col ?? 0) - (b.col ?? 0));
    if (!q) return base;
    return base.filter((el) => {
      const name = (el.name ?? '').toLowerCase();
      const symbol = (el.symbol ?? '').toLowerCase();
      return name.includes(q) || symbol.includes(q);
    });
  }, [elements, query]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber == null) return null;
    return filteredElements.find((el) => el.atomicNumber === selectedAtomicNumber) ?? null;
  }, [filteredElements, selectedAtomicNumber]);

  useEffect(() => {
    if (selectedAtomicNumber == null) return;
    const stillVisible = filteredElements.some((el) => el.atomicNumber === selectedAtomicNumber);
    if (!stillVisible) {
      setSelectedAtomicNumber(filteredElements[0]?.atomicNumber ?? null);
    }
  }, [filteredElements, selectedAtomicNumber]);

  useEffect(() => {
    if (selectedAtomicNumber != null) return;
    if (filteredElements.length > 0) {
      setSelectedAtomicNumber(filteredElements[0].atomicNumber ?? null);
    }
  }, [filteredElements, selectedAtomicNumber]);

  const legendCategories = useMemo(() => {
    const seen = new Set<string>();
    const items: string[] = [];
    elements.forEach((el) => {
      const cat = normalizeCategory(el.category);
      if (!seen.has(cat)) {
        seen.add(cat);
        items.push(cat);
      }
    });
    return items;
  }, [elements]);

  return (
    <Container maxWidth="full" padding={0}>
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Card padding="var(--ggui-spacing-6, 24px)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-2, 8px)">
            <Heading level={2}>Periodic Table of Elements</Heading>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Search by name or symbol, then select an element to inspect its properties and category.
            </Text>
            <Input
              label="Search elements"
              type="search"
              value={query}
              onChange={setQuery}
              placeholder="Search by name or symbol"
              aria-label="Search elements"
            />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4, 16px)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Box
              style={{
                overflowX: 'auto',
                paddingBottom: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              <Box
                role="grid"
                aria-label="Periodic table of elements"
                style={{
