                  gridTemplateColumns: 'repeat(18, minmax(4.5rem, 1fr))',
                  gridAutoRows: 'minmax(5rem, auto)',
                  gap: 'var(--ggui-spacing-2, 8px)',
                  minWidth: 'min-content',
                  alignItems: 'stretch',
                }}
              >
                {filteredElements.map((el) => {
                  const category = normalizeCategory(el.category);
                  const styleSet = categoryStyles[category] ?? categoryStyles.unknown;
                  const isSelected = selectedElement?.atomicNumber === el.atomicNumber;
                  const label = `${el.atomicNumber ?? '-'} ${el.symbol ?? '?'} ${el.name ?? 'Unknown'}`;
                  return (
                    <Box
                      key={`${el.atomicNumber ?? 'x'}-${el.symbol ?? 'x'}-${el.row ?? 'r'}-${el.col ?? 'c'}`}
                      role="gridcell"
                      tabIndex={0}
                      aria-selected={isSelected}
                      aria-label={label}
                      onClick={() => setSelectedAtomicNumber(el.atomicNumber ?? null)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.preventDefault();
                          setSelectedAtomicNumber(el.atomicNumber ?? null);
                        }
                      }}
                      style={{
                        gridRow: el.row ?? 1,
                        gridColumn: el.col ?? 1,
                        minHeight: '5rem',
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        border: `1px solid ${isSelected ? 'var(--ggui-color-primary-600, #0284c7)' : styleSet.border}`,
                        background: isSelected ? 'var(--ggui-color-primary-50, #f0f9ff)' : styleSet.background,
                        color: styleSet.color,
                        boxShadow: isSelected
                          ? 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))'
                          : 'var(--ggui-shape-shadow-sm, 0 1px 2px 0 rgba(0,0,0,0.05))',
                        padding: 'var(--ggui-spacing-2, 8px)',
                        cursor: 'pointer',
                        position: 'relative',
                        display: 'flex',
                        flexDirection: 'column',
                        justifyContent: 'center',
                        textAlign: 'center',
                        transition: 'background-color 200ms ease, border-color 200ms ease, box-shadow 200ms ease, transform 200ms ease',
                        outline: 'none',
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.transform = 'translateY(-1px)';
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.transform = 'translateY(0)';
                      }}
                      onFocus={(e) => {
                        e.currentTarget.style.outline = '2px solid var(--ggui-color-primary-600, #0284c7)';
                        e.currentTarget.style.outlineOffset = '2px';
                      }}
                      onBlur={(e) => {
                        e.currentTarget.style.outline = 'none';
                      }}
                    >
                      <Text
                        variant="caption"
                        color="inherit"
                        is="span"
                        style={{
                          position: 'absolute',
                          top: 'var(--ggui-spacing-1, 4px)',
                          left: 'var(--ggui-spacing-1, 4px)',
                        }}
                      >
                        {el.atomicNumber ?? '-'}
                      </Text>
                      <Stack gap="var(--ggui-spacing-1, 4px)" align="center" justify="center">
                        <Text variant="bodyLarge" weight="bold" color="inherit">
                          {el.symbol ?? '?'}
                        </Text>
                        <Text variant="caption" color="inherit" truncate>
                          {el.name ?? 'Unknown'}
                        </Text>
                      </Stack>
                    </Box>
                  );
                })}
              </Box>
            </Box>

            <Divider margin={0} />

            <Card padding="var(--ggui-spacing-4, 16px)" shadow="none" radius="md" border>
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Heading level={4}>Element Details</Heading>
                <Box
                  aria-live="polite"
                  style={{
                    minHeight: '6rem',
                  }}
                >
                  {selectedElement ? (
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center" wrap>
                        <Heading level={3}>{selectedElement.name ?? 'Unknown'}</Heading>
                        <Badge variant="primary" size="sm">
                          {selectedElement.symbol ?? '?'}
                        </Badge>
                        <Badge
                          variant={normalizeCategory(selectedElement.category) === 'unknown' ? 'secondary' : 'info'}
                          size="sm"
                        >
                          {formatCategoryLabel(selectedElement.category)}
                        </Badge>
                      </Stack>
                      <Text variant="bodySmall">
                        <strong>Atomic Number:</strong> {formatDetailValue(selectedElement.atomicNumber)}
                      </Text>
                      <Text variant="bodySmall">
                        <strong>Atomic Weight:</strong> {formatAtomicWeight(selectedElement.atomicWeight)}
                      </Text>
                      <Text variant="bodySmall">
                        <strong>Category:</strong> {formatCategoryLabel(selectedElement.category)}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        <strong>Symbol:</strong> {selectedElement.symbol ?? '?'}
