                </Box>
              </Stack>
            </Card>

            <Card padding="var(--ggui-spacing-4, 16px)" shadow="none" radius="md" border>
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Heading level={4}>Legend</Heading>
                <Box
                  style={{
                    display: 'flex',
                    flexWrap: 'wrap',
                    gap: 'var(--ggui-spacing-2, 8px)',
                  }}
                >
                  {legendCategories.map((category) => {
                    const styles = categoryStyles[category] ?? categoryStyles.unknown;
                    return (
                      <Badge
                        key={category}
                        variant="secondary"
                        size="sm"
