import React, { useEffect, useMemo, useState } from 'react';
import {
  Alert,
  Badge,
  Box,
  Button,
  Card,
  Container,
  Divider,
  Heading,
  Icon,
  Input,
  MotionKeyframes,
  Spinner,
  Stack,
  Table,
  Tabs,
  Text,
} from '@ggui-ai/design/primitives';

interface Props {
  product: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: unknown[];
    reviews?: unknown[];
  };
  onSubmit?: (payload: { productId: string; quantity: number }) => Promise<void> | void;
  addToCart?: (payload: { productId: string; quantity: number }) => Promise<void> | void;
}

type SpecItem = { key?: string; value?: string };
type ReviewItem = { author?: string; rating?: number; text?: string; date?: string };

function clamp(value: number, min: number, max: number) {
  return Math.min(max, Math.max(min, value));
}

function formatPrice(price: number, currency?: string) {
  const code = currency ?? 'USD';
  try {
    return new Intl.NumberFormat(undefined, { style: 'currency', currency: code }).format(price);
  } catch {
    return `${code} ${price.toFixed(2)}`;
  }
}

function formatDate(date?: string) {
  if (!date) return '';
  const parsed = new Date(date);
  if (Number.isNaN(parsed.getTime())) return date;
  return parsed.toLocaleDateString();
}

function StarRow({ value, ariaLabel }: { value: number; ariaLabel: string }) {
  const filledCount = Math.round(value);
  return (
    <span aria-label={ariaLabel} style={{ display: 'inline-flex', gap: 'var(--ggui-spacing-1, 4px)' }}>
      {Array.from({ length: 5 }, (_, index) => (
        <Icon
          key={index}
          name="star"
          size={18}
          color={index < filledCount ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-outline, #d4d4d8)'}
        />
      ))}
    </span>
  );
}

function clampQuantityText(text: string, stock: number) {
  const raw = text.trim();
  if (!raw) return { value: 1, error: undefined as string | undefined };
  const parsed = Number(raw);
  if (!Number.isInteger(parsed)) return { value: 1, error: 'Quantity must be a whole number.' };
  if (parsed < 1) return { value: 1, error: 'Quantity must be at least 1.' };
  if (stock > 0 && parsed > stock) return { value: stock, error: `Quantity cannot exceed available stock (${stock}).` };
  return { value: parsed, error: undefined };
}

export default function GeneratedComponent(props: Props) {
  const product = props.product;
  const productId = product.id ?? '';
  const productName = product.name ?? 'Product';
  const price = product.price ?? 0;
  const currency = product.currency ?? 'USD';
  const rating = clamp(product.rating ?? 0, 0, 5);
  const reviewCount = product.reviewCount ?? 0;
  const stock = product.stock ?? 0;
  const description = product.description ?? '';
  const specifications = (product.specifications ?? []) as SpecItem[];
  const reviews = (product.reviews ?? []) as ReviewItem[];

  const [isMobile, setIsMobile] = useState(false);
  const [quantity, setQuantity] = useState(1);
  const [quantityInput, setQuantityInput] = useState('1');
  const [quantityError, setQuantityError] = useState<string | undefined>(undefined);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState<string | undefined>(undefined);
  const [submitError, setSubmitError] = useState<string | undefined>(undefined);
  const [activeTabKey, setActiveTabKey] = useState('description');

  const maxQty = Math.max(1, stock);
  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;
  const canSubmit = !isOutOfStock && !quantityError && !isSubmitting && quantity >= 1 && quantity <= maxQty;

  useEffect(() => {
    const checkMobile = () => {
      if (typeof globalThis !== 'undefined' && typeof globalThis.innerWidth === 'number') {
        setIsMobile(globalThis.innerWidth < 768);
      }
    };
    checkMobile();
  }, []);

  useEffect(() => {
    if (quantity > maxQty) {
      setQuantity(maxQty);
      setQuantityInput(String(maxQty));
    }
    if (stock <= 0) {
      setQuantity(1);
      setQuantityInput('1');
    }
  }, [maxQty, quantity, stock]);

  const tabItems = useMemo(
    () => [
      {
        key: 'description',
        label: 'Description',
        content: (
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Heading level={4}>Product Description</Heading>
            <Text variant="body">{description}</Text>
          </Stack>
        ),
      },
      {
        key: 'specifications',
        label: 'Specifications',
        content: (
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Heading level={4}>Product Specifications</Heading>
            <Table
              columns={[
                {
                  key: 'key',
                  header: 'Key',
                  width: '40%',
                  render: (value) => <Text variant="bodySmall">{String(value ?? '')}</Text>,
                },
                {
                  key: 'value',
                  header: 'Value',
                  width: '60%',
                  render: (value) => <Text variant="bodySmall">{String(value ?? '')}</Text>,
                },
              ]}
              data={specifications}
              striped
              hoverable
              compact
              bordered
              caption="Product specifications"
            />
          </Stack>
        ),
      },
      {
        key: 'reviews',
        label: 'Reviews',
        content: (
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Heading level={4}>Customer Reviews</Heading>
            {reviews.length === 0 ? (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No reviews available.
              </Text>
            ) : (
              <Stack gap={0}>
                {reviews.map((review, index) => (
                  <Box
                    key={`${review.author ?? 'review'}-${index}`}
                    paddingY="var(--ggui-spacing-4, 16px)"
                    style={{
                      transition: 'background-color 200ms ease, border-color 200ms ease',
                      borderTop: index === 0 ? 'none' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-2, 8px)">
                      <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center" wrap>
                        <Heading level={6}>{review.author ?? 'Anonymous'}</Heading>
                        <StarRow value={review.rating ?? 0} ariaLabel={`Rated ${review.rating ?? 0} out of 5`} />
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {formatDate(review.date)}
                        </Text>
                      </Stack>
                      <Text variant="bodySmall">{review.text ?? ''}</Text>
                    </Stack>
                  </Box>
                ))}
              </Stack>
            )}
          </Stack>
        ),
      },
    ],
    [description, reviews, specifications]
  );

  const handleQuantityChange = (value: string) => {
    setQuantityInput(value);
    const parsed = clampQuantityText(value, stock);
    setQuantityError(parsed.error);
    setQuantity(parsed.value);
  };

  const handleQuantityBlur = () => {
    const parsed = clampQuantityText(quantityInput, stock);
    setQuantity(parsed.value);
    setQuantityInput(String(parsed.value));
    setQuantityError(parsed.error);
  };

  const updateQuantity = (next: number) => {
    const clamped = clamp(next, 1, maxQty);
    setQuantity(clamped);
    setQuantityInput(String(clamped));
    setQuantityError(undefined);
  };

  const handleSubmit = async () => {
    const parsed = clampQuantityText(quantityInput, stock);
    if (isOutOfStock) {
      setSubmitError('This product is currently out of stock.');
      setSubmitSuccess(undefined);
      return;
    }
    if (parsed.error) {
      setQuantityError(parsed.error);
      setSubmitError(undefined);
      setSubmitSuccess(undefined);
      return;
    }

    const payload = { productId, quantity: parsed.value };
    setIsSubmitting(true);
    setSubmitError(undefined);
    setSubmitSuccess(undefined);

    try {
      await props.onSubmit?.(payload);
      await props.addToCart?.(payload);
      setSubmitSuccess('Added to cart successfully.');
    } catch {
      setSubmitError('Unable to add this product to cart.');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap="var(--ggui-spacing-6, 24px)" aria-label="Product details">
        <Card shadow="sm" padding="var(--ggui-spacing-6, 24px)" radius="lg" border>
          <Stack
            direction={isMobile ? 'vertical' : 'horizontal'}
            gap="var(--ggui-spacing-6, 24px)"
            align="stretch"
          >
            <Box
              style={{ flex: isMobile ? undefined : '0 0 40%' }}
              role="img"
              aria-label={productName}
              background="var(--ggui-color-primary-50, #f0f9ff)"
              borderRadius="var(--ggui-shape-radius-lg, 12px)"
            >
              <Box
                padding="var(--ggui-spacing-8, 32px)"
                style={{
                  minHeight: '220px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  textAlign: 'center',
                  border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                  borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                }}
              >
                <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-900, #0c4a6e)">
                  {productName}
                </Text>
              </Box>
            </Box>

            <Stack gap="var(--ggui-spacing-4, 16px)" style={{ flex: 1 }}>
              <Stack gap="var(--ggui-spacing-2, 8px)">
                <Heading level={2}>{productName}</Heading>
                <Text variant="bodyLarge" weight="bold">
                  {formatPrice(price, currency)}
                </Text>
              </Stack>

              <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center" wrap>
                <StarRow value={rating} ariaLabel={`Rated ${rating} out of 5`} />
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {reviewCount} review{reviewCount === 1 ? '' : 's'}
                </Text>
              </Stack>

              <Badge
                variant={isOutOfStock ? 'error' : isLowStock ? 'warning' : 'success'}
                size="md"
              >
                {isOutOfStock ? 'Out of Stock' : isLowStock ? 'Low Stock' : 'In Stock'}
              </Badge>

              <Divider margin="var(--ggui-spacing-2, 8px)" />

              <Text variant="body">{description}</Text>
            </Stack>
          </Stack>
        </Card>

        <Card shadow="sm" padding="var(--ggui-spacing-6, 24px)" radius="lg" border>
          <Tabs
            items={tabItems}
            activeKey={activeTabKey}
            onChange={setActiveTabKey}
            variant="line"
            size="md"
            fullWidth={isMobile}
          />
        </Card>

        <Card shadow="sm" padding="var(--ggui-spacing-6, 24px)" radius="lg" border>
          <Stack gap="var(--ggui-spacing-4, 16px)">
            <Heading level={4}>Purchase</Heading>

            <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="end" wrap>
              <Button
                variant="outline"
                size="sm"
                aria-label="Decrease quantity"
                disabled={isSubmitting || isOutOfStock || quantity <= 1}
                onClick={() => updateQuantity(quantity - 1)}
              >
                -
              </Button>

              <Box style={{ flex: isMobile ? '1 1 100%' : '0 1 180px' }}>
                <Input
                  label="Quantity"
                  type="number"
                  value={quantityInput}
                  onChange={handleQuantityChange}
                  onBlur={handleQuantityBlur}
                  min={1}
                  max={maxQty}
                  disabled={isSubmitting || isOutOfStock}
                  error={quantityError}
                  helperText={
                    isOutOfStock
                      ? 'Quantity is disabled while the product is out of stock.'
                      : `Available stock: ${stock}`
                  }
                />
              </Box>

              <Button
                variant="outline"
                size="sm"
                aria-label="Increase quantity"
                disabled={isSubmitting || isOutOfStock || quantity >= maxQty}
                onClick={() => updateQuantity(quantity + 1)}
              >
                +
              </Button>
            </Stack>

            <Button
              variant="primary"
              size="md"
              fullWidth={isMobile}
              aria-label="Add to cart"
              disabled={!canSubmit}
              loading={isSubmitting}
              onClick={handleSubmit}
              rightIcon={isSubmitting ? <Spinner size={16} color="currentColor" /> : undefined}
            >
              Add to Cart
            </Button>

            {submitSuccess ? (
              <Alert variant="success" title="Success">
                {submitSuccess}
              </Alert>
            ) : null}
            {submitError ? (
              <Alert variant="error" title="Error">
                {submitError}
              </Alert>
            ) : null}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Avatar, Badge, Button, Card, Container, Input, MotionKeyframes, Spinner, Stack, Text, Heading } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Initial messages to display on mount */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

type ChatMessage = { sender?: string; text?: string; timestamp?: string };

type StreamPayload =
  | {
      type?: string;
      event?: string;
      kind?: string;
      message?: ChatMessage;
      data?: unknown;
      sender?: string;
      text?: string;
      timestamp?: string;
      active?: boolean;
      typing?: { sender?: string; active?: boolean };
    }
  | ChatMessage
  | {
      sender?: string;
      active?: boolean;
      type?: string;
      event?: string;
      kind?: string;
      typing?: { sender?: string; active?: boolean };
      data?: unknown;
    };

declare global {
  interface WindowEventMap {
    'ggui:agent-data': CustomEvent<StreamPayload>;
  }
}

const __GGUI_STREAM_SPEC__ = {
  description: 'Real-time chat events from the agent',
  events: {
    message: {
      description: 'New message from another participant — append to message list',
      schema: {
        type: 'object',
        properties: {
          sender: { type: 'string' },
          text: { type: 'string' },
          timestamp: { type: 'string' },
        },
      },
      example: {
        sender: 'Alice',
        text: 'Just pushed the latest changes',
        timestamp: '2026-03-15T14:10:00Z',
      },
    },
    typing: {
      description: 'Typing indicator — show/hide based on active flag',
      schema: {
        type: 'object',
        properties: {
          sender: { type: 'string' },
          active: { type: 'boolean' },
        },
      },
      example: {
        sender: 'Bob',
        active: true,
      },
    },
  },
};

function formatTimestamp(ts?: string) {
  const d = ts ? new Date(ts) : new Date();
  if (Number.isNaN(d.getTime())) return '';
  return d.toLocaleString([], { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });
}

function isSameSender(a?: string, b?: string) {
  return (a ?? '') === (b ?? '');
}

function extractMessage(payload: StreamPayload): ChatMessage | null {
  const typed = payload as {
    type?: string;
    event?: string;
    kind?: string;
    message?: ChatMessage;
    data?: unknown;
    sender?: string;
    text?: string;
    timestamp?: string;
  };
  const type = typed.type ?? typed.event ?? typed.kind;
  const raw = typed.data ?? payload;

  if (type === 'message') {
    const candidate = typed.message ?? (typeof raw === 'object' && raw ? (raw as ChatMessage) : null);
    if (candidate && (candidate.sender || candidate.text || candidate.timestamp)) return candidate;
  }

  if (typeof raw === 'object' && raw) {
    const candidate = raw as ChatMessage;
    if (candidate.sender || candidate.text || candidate.timestamp) return candidate;
  }

  if (typed.sender || typed.text || typed.timestamp) return { sender: typed.sender, text: typed.text, timestamp: typed.timestamp };
  return null;
}

function extractTyping(payload: StreamPayload): { sender?: string; active?: boolean } | null {
  const typed = payload as {
    type?: string;
    event?: string;
    kind?: string;
    typing?: { sender?: string; active?: boolean };
    data?: unknown;
    sender?: string;
    active?: boolean;
  };
  const type = typed.type ?? typed.event ?? typed.kind;
  const raw = typed.data ?? payload;

  if (type === 'typing') {
    const candidate = typed.typing ?? (typeof raw === 'object' && raw ? (raw as { sender?: string; active?: boolean }) : null);
    if (candidate && typeof candidate.sender === 'string') return candidate;
  }

  if (
    typeof raw === 'object' &&
    raw &&
    typeof (raw as { sender?: string }).sender === 'string' &&
    typeof (raw as { active?: boolean }).active === 'boolean'
  ) {
    return raw as { sender?: string; active?: boolean };
  }

  if (typeof typed.sender === 'string' && typeof typed.active === 'boolean') return { sender: typed.sender, active: typed.active };
  return null;
}

export default function GeneratedComponent(props: Props) {
  const initialMessages = props.messages ?? [];
  const [messages, setMessages] = useState<ChatMessage[]>(initialMessages);
  const [text, setText] = useState('');
  const [typingSender, setTypingSender] = useState<string | null>(null);
  const bottomRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setMessages(initialMessages);
  }, [initialMessages]);

  useEffect(() => {
    const handleStream = (detail: StreamPayload | null | undefined) => {
      if (!detail) return;
      const messageCandidate = extractMessage(detail);
      if (messageCandidate) {
        setMessages((prev) => [...prev, messageCandidate]);
        return;
      }
      const typingCandidate = extractTyping(detail);
      if (typingCandidate && typeof typingCandidate.sender === 'string') {
        setTypingSender(typingCandidate.active ? typingCandidate.sender : null);
      }
    };

    const onStream = (event: Event) => {
      handleStream((event as CustomEvent<StreamPayload>).detail);
    };

    if (typeof globalThis !== 'undefined') {
      globalThis.addEventListener('ggui:agent-data', onStream as EventListener);
      return () => globalThis.removeEventListener('ggui:agent-data', onStream as EventListener);
    }

    return undefined;
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth', block: 'end' });
  }, [messages, typingSender]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: ChatMessage[] }> = [];
    for (const msg of messages) {
      const last = groups[groups.length - 1];
      if (last && isSameSender(last.sender, msg.sender)) last.items.push(msg);
      else groups.push({ sender: msg.sender, items: [msg] });
    }
    return groups;
  }, [messages]);

  const participantBadge = props.participantCount ?? 0;
  const canSend = text.trim().length > 0;

  const sendMessage = () => {
    const value = text.trim();
    if (!value) return;
    const payload = { text: value, timestamp: new Date().toISOString() };
    (props as Props & { sendMessage?: (payload: { text: string; timestamp: string }) => void }).sendMessage?.(payload);
    setText('');
  };

  return (
    <>
      <MotionKeyframes />
      <div style={{ display: 'none' }} aria-hidden="true">
        {JSON.stringify(__GGUI_STREAM_SPEC__)}
      </div>

      <Container maxWidth="xl" padding={0}>
        <Card shadow="md" padding={0} radius="lg" border>
          <div
            style={{
              display: 'flex',
              flexDirection: 'column',
              minHeight: '100%',
              background: 'var(--ggui-color-surface, #fafafa)',
            }}
          >
            <div
              style={{
                padding: 'var(--ggui-spacing-4, 16px)',
                borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                background: 'var(--ggui-color-primary-50, #f0f9ff)',
              }}
            >
              <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                <Stack gap="var(--ggui-spacing-1, 4px)" direction="vertical">
                  <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                    {props.title}
                  </Heading>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    Real-time conversation
                  </Text>
                </Stack>
                <div style={{ flex: 1 }} />
                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                  <Badge variant="primary" size="sm">
                    {participantBadge} participant{participantBadge === 1 ? '' : 's'}
                  </Badge>
                  {typingSender ? (
                    <Badge variant="info" size="sm">
                      {typingSender} is typing…
                    </Badge>
                  ) : null}
                </Stack>
              </Stack>
            </div>

            <div
              style={{
                flex: 1,
                overflowY: 'auto',
                padding: 'var(--ggui-spacing-4, 16px)',
                display: 'flex',
                flexDirection: 'column',
                gap: 'var(--ggui-spacing-4, 16px)',
                minHeight: 0,
              }}
            >
              {groupedMessages.map((group, groupIndex) => (
                <div key={`${group.sender ?? 'unknown'}-${groupIndex}`} style={{ display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-2, 8px)' }}>
                  {group.items.map((msg, index) => {
                    const own = isSameSender(msg.sender, props.currentUser);
                    const firstInGroup = index === 0;
                    const lastInGroup = index === group.items.length - 1;

                    return (
                      <div key={`${msg.sender ?? 'unknown'}-${msg.timestamp ?? ''}-${index}`} style={{ display: 'flex', justifyContent: own ? 'flex-end' : 'flex-start' }}>
                        <div
                          style={{
                            maxWidth: 'min(80%, 640px)',
                            display: 'flex',
                            flexDirection: own ? 'row-reverse' : 'row',
                            alignItems: 'flex-end',
                            gap: 'var(--ggui-spacing-2, 8px)',
                          }}
                        >
                          {!own ? <Avatar name={msg.sender ?? 'Participant'} size="sm" shape="circle" /> : <div style={{ width: '32px', flexShrink: 0 }} />}

                          <div
                            style={{
                              display: 'flex',
                              flexDirection: 'column',
                              alignItems: own ? 'flex-end' : 'flex-start',
                              gap: 'var(--ggui-spacing-1, 4px)',
                            }}
                          >
                            {firstInGroup ? (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align={own ? 'right' : 'left'} is="span">
                                {msg.sender ?? 'Unknown'}
                              </Text>
                            ) : (
                              <div style={{ height: '1px' }} />
                            )}

                            <div
                              style={{
                                background: own ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                                color: own ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)',
                                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                                padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                                boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px 0 var(--ggui-color-outlineVariant, #e4e4e7))',
                                border: own ? '1px solid transparent' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                                transition: 'background-color 200ms ease, box-shadow 200ms ease, border-color 200ms ease',
                              }}
                            >
                              <Text variant="body" color={own ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurface, #18181b)'} is="div">
                                {msg.text ?? ''}
                              </Text>
                            </div>

                            {lastInGroup ? (
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align={own ? 'right' : 'left'} is="span">
                                {formatTimestamp(msg.timestamp)}
                              </Text>
                            ) : null}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              ))}

              {typingSender ? (
                <div style={{ display: 'flex', justifyContent: 'flex-start' }}>
                  <div
                    style={{
                      background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      color: 'var(--ggui-color-onSurfaceVariant, #52525b)',
                      padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)',
                      borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                      border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                      display: 'inline-flex',
                      alignItems: 'center',
                      gap: 'var(--ggui-spacing-2, 8px)',
                    }}
                  >
                    <Spinner size={16} />
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {typingSender} is typing
                    </Text>
                  </div>
                </div>
              ) : null}

              <div ref={bottomRef} />
            </div>

            <div
              style={{
                borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                padding: 'var(--ggui-spacing-4, 16px)',
                background: 'var(--ggui-color-surface, #fafafa)',
              }}
            >
              <Stack direction="horizontal" align="end" gap="var(--ggui-spacing-2, 8px)">
                <div style={{ flex: 1 }}>
                  <Input
                    label="Message"
                    placeholder="Type a message..."
                    value={text}
                    onChange={setText}
                    onKeyDown={(e: React.KeyboardEvent<HTMLInputElement>) => {
                      if (e.key === 'Enter' && !e.shiftKey) {
                        e.preventDefault();
                        sendMessage();
                      }
                    }}
                    aria-label="Compose message"
                  />
                </div>
                <Button variant="primary" size="md" disabled={!canSend} onClick={sendMessage} aria-label="Send message">
                  Send
                </Button>
              </Stack>
            </div>
          </div>
        </Card>
      </Container>
    </>
  );
}

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { Badge, Box, Card, Container, Heading, MotionKeyframes, Spinner, Stack, Text } from '@ggui-ai/design/primitives';

interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>;
}

type StockRow = {
  symbol: string;
  name: string;
  price: number;
  change: number;
  changePercent: number;
};

type StreamEventPayload =
  | { type?: 'priceUpdate'; symbol?: string; price?: number; change?: number; changePercent?: number }
  | { type?: 'marketStatus'; status?: string; timestamp?: string }
  | Record<string, unknown>;

const money = new Intl.NumberFormat(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const percent = new Intl.NumberFormat(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });

function safeStock(stock: { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }): StockRow {
  return {
    symbol: stock.symbol ?? '—',
    name: stock.name ?? 'Unknown Company',
    price: stock.price ?? 0,
    change: stock.change ?? 0,
    changePercent: stock.changePercent ?? 0,
  };
}

function formatTimestamp(date: Date): string {
  return date.toLocaleTimeString([], {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });
}

function statusLabel(status: string): string {
  const normalized = status.trim().toLowerCase();
  if (normalized === 'open') return 'Open';
  if (normalized === 'closed') return 'Closed';
  if (normalized === 'pre-market') return 'Pre-market';
  if (normalized === 'after-hours') return 'After-hours';
  return status;
}

function StockCard({ stock, flashKey }: { stock: StockRow; flashKey: number }) {
  const positive = stock.change > 0;
  const negative = stock.change < 0;
  const accent = positive
    ? 'var(--ggui-color-success, #16a34a)'
    : negative
      ? 'var(--ggui-color-error, #dc2626)'
      : 'var(--ggui-color-outline, #d4d4d8)';
  const tint = positive
    ? 'var(--ggui-color-success-50, #f0fdf4)'
    : negative
      ? 'var(--ggui-color-error-50, #fef2f2)'
      : 'var(--ggui-color-primary-50, #f0f9ff)';
  const textColor = positive
    ? 'var(--ggui-color-success, #16a34a)'
    : negative
      ? 'var(--ggui-color-error, #dc2626)'
      : 'var(--ggui-color-onSurfaceVariant, #52525b)';

  return (
    <Card shadow="sm" radius="lg" padding={0} border>
      <Box
        key={flashKey}
        style={{
          animation: 'ggui-fadeIn 220ms ease-out both',
          borderLeft: `3px solid ${accent}`,
          transition: 'background-color 200ms ease, border-color 200ms ease, transform 200ms ease, box-shadow 200ms ease',
        }}
      >
        <Box
          padding={16}
          background={tint}
          borderRadius={12}
          style={{
            backgroundColor: tint,
          }}
        >
          <Stack gap={12}>
            <Stack direction="horizontal" align="center" justify="between" gap={12}>
              <div>
                <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">
                  {stock.symbol}
                </Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {stock.name}
                </Text>
              </div>
              <Badge variant={positive ? 'success' : negative ? 'error' : 'default'} size="sm" pill>
                {positive ? 'Up' : negative ? 'Down' : 'Flat'}
              </Badge>
            </Stack>

            <Stack gap={8}>
              <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Current Price
              </Text>
              <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface, #18181b)" is="div">
                ${money.format(stock.price)}
              </Text>
            </Stack>

            <Stack direction="horizontal" align="center" justify="between" gap={8}>
              <Text variant="body" weight="semibold" color={textColor} is="div">
                {stock.change >= 0 ? '+' : ''}
                {money.format(stock.change)}
              </Text>
              <Text variant="body" weight="semibold" color={textColor} is="div">
                <span aria-hidden="true" style={{ marginRight: 'var(--ggui-spacing-1, 4px)' }}>
                  {positive ? '▲' : negative ? '▼' : '•'}
                </span>
                {stock.changePercent >= 0 ? '+' : ''}
                {percent.format(stock.changePercent)}%
              </Text>
            </Stack>
          </Stack>
        </Box>
      </Box>
    </Card>
  );
}

export default function GeneratedComponent(props: Props) {
  const [stocksState, setStocksState] = useState<StockRow[]>(() => props.stocks.map(safeStock));
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [connectionState, setConnectionState] = useState<'connecting' | 'live' | 'idle'>('connecting');
  const [updatePulse, setUpdatePulse] = useState<Record<string, number>>({});
  const [marketStatus, setMarketStatus] = useState<string>('connecting');
  const updateCounterRef = useRef(0);

  useEffect(() => {
    setStocksState(props.stocks.map(safeStock));
    setLastUpdated(new Date());
  }, [props.stocks]);

  useEffect(() => {
    const tick = setInterval(() => setLastUpdated(new Date()), 1000);
    return () => clearInterval(tick);
  }, []);

  useEffect(() => {
    const onAgentData = (event: Event) => {
      const customEvent = event as CustomEvent<StreamEventPayload>;
      const payload = customEvent.detail;
      if (!payload || typeof payload !== 'object') return;

      const type = (payload as { type?: string }).type;
      if (type === 'marketStatus') {
        setConnectionState('live');
        const status = (payload as { status?: string }).status;
        if (status) setMarketStatus(status);
        const ts = (payload as { timestamp?: string }).timestamp;
        if (ts) {
          const parsed = new Date(ts);
          if (!Number.isNaN(parsed.getTime())) setLastUpdated(parsed);
        }
        return;
      }

      const symbol = (payload as { symbol?: string }).symbol;
      const price = (payload as { price?: number }).price;
      const change = (payload as { change?: number }).change;
      const changePercent = (payload as { changePercent?: number }).changePercent;

      if (!symbol) return;

      setConnectionState('live');
      setStocksState((prev) =>
        prev.map((stock) =>
          stock.symbol === symbol
            ? {
                ...stock,
                price: typeof price === 'number' ? price : stock.price,
                change: typeof change === 'number' ? change : stock.change,
                changePercent: typeof changePercent === 'number' ? changePercent : stock.changePercent,
              }
            : stock,
        ),
      );

      updateCounterRef.current += 1;
      const pulseId = updateCounterRef.current;
      setUpdatePulse((prev) => ({ ...prev, [symbol]: pulseId }));
      setLastUpdated(new Date());
    };

    globalThis.addEventListener('ggui:agent-data', onAgentData as EventListener);
    const connectingTimer = setTimeout(() => setConnectionState('idle'), 900);
    return () => {
      globalThis.removeEventListener('ggui:agent-data', onAgentData as EventListener);
      clearTimeout(connectingTimer);
    };
  }, []);

  const displayStocks = useMemo(() => stocksState, [stocksState]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={16}>
        <Card shadow="md" padding={16} radius="lg">
          <Stack direction="horizontal" align="center" justify="between" gap={16} wrap>
            <Stack gap={4}>
              <Heading level={1}>Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Live stock ticker dashboard
              </Text>
            </Stack>

            <Stack direction="horizontal" align="center" gap={12} wrap>
              <Badge variant={connectionState === 'live' ? 'success' : 'warning'} size="sm" pill>
                {connectionState === 'live' ? 'Connected' : connectionState === 'connecting' ? 'Connecting' : 'Idle'}
              </Badge>
              <Badge variant="primary" size="sm" pill>
                {statusLabel(marketStatus)}
              </Badge>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Last Updated: {formatTimestamp(lastUpdated)}
              </Text>
            </Stack>
          </Stack>
        </Card>

        {displayStocks.length === 0 ? (
          <Card shadow="sm" padding={24} radius="lg">
            <Stack align="center" gap={12}>
              <Spinner size={28} color="var(--ggui-color-primary-600, #0284c7)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                No stocks available.
              </Text>
            </Stack>
          </Card>
        ) : (
          <div
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
              gap: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            {displayStocks.map((stock) => (
              <div key={stock.symbol} style={{ position: 'relative' }}>
                <StockCard stock={stock} flashKey={updatePulse[stock.symbol] ?? 0} />
              </div>
            ))}
          </div>
        )}
      </Stack>
      <div style={{ display: 'none' }}>
        __GGUI_STREAM_SPEC__
        {'{"events":{"priceUpdate":{"description":"Updated price data for one or more stocks","schema":{"type":"object","properties":{"symbol":{"type":"string"},"price":{"type":"number"},"change":{"type":"number"},"changePercent":{"type":"number"}}},"example":{"symbol":"AAPL","price":179.1,"change":2.92,"changePercent":1.66}},"marketStatus":{"description":"Market open/closed status update","schema":{"type":"object","properties":{"status":{"type":"string","enum":["open","closed","pre-market","after-hours"]},"timestamp":{"type":"string"}}},"example":{"status":"open","timestamp":"2026-03-15T16:30:00Z"}}}}'}
        __GGUI_STREAM_SPEC_END__
      </div>
    </Container>
  );
}
